solution_code:
#include <iostream>

int sumDigits(int n)
{
    if (n < 10)
        return n;
    return (n % 10) + sumDigits(n / 10);
}

int main()
{
    int n{};
    std::cin >> n;
    std::cout << sumDigits(n) << '\n';
    return 0;
}

